import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String input = scanner.nextLine(); // Use nextLine() to allow spaces in input

        int maxLength = 10; // Maximum length for the buffer
        char[] buffer = new char[maxLength];
        int i = 0;

        for (char c : input.toCharArray()) {
            if (i < maxLength) { // Check if there is space left in the buffer
                buffer[i++] = c;
            } else {
                break; // Stop reading characters if the buffer is full
            }
        }

        System.out.println("Your name is: " + new String(buffer, 0, i)); // Print only the valid portion of the buffer
    }
}

